+        let b = UFuncArray::new(vec![2], vec![2.0, 3.0], DType::F64).unwrap();
+        let c = UFuncArray::new(vec![1, 2], vec![4.0, 5.0], DType::F64).unwrap();
+        let r = UFuncArray::concatenate_flat(&[&a, &b, &c]).unwrap();
+        assert_eq!(r.shape(), &[5]);
