+    #[test]
+    fn clip_nan_propagation() {
+        // np.clip([nan, 1, 2], 0, 3) → [nan, 1, 2]
+        let a = UFuncArray::new(vec![3], vec![f64::NAN, 1.0, 2.0], DType::F64).unwrap();
