+    #[test]
+    fn sort_nan_goes_to_end() {
+        // np.sort([3, nan, 1, nan, 2]) → [1, 2, 3, nan, nan]
+        let a = UFuncArray::new(vec![5], vec![3.0, f64::NAN, 1.0, f64::NAN, 2.0], DType::F64).unwrap();
